function _setInterestRateModelFresh(InterestRateModel newInterestRateModel) internal returns (uint) {

    // Used to store old model for use in the event that is emitted on success
    InterestRateModel oldInterestRateModel;

    // Check caller is admin
    if (msg.sender != admin) {
        revert SetInterestRateModelOwnerCheck();
    }

    // We fail gracefully unless market's block number equals current block number
    if (accrualBlockNumber != getBlockNumber()) {
        revert SetInterestRateModelFreshCheck();
    }

    // Track the market's current interest rate model
    oldInterestRateModel = interestRateModel;

    // Ensure invoke newInterestRateModel.isInterestRateModel() returns true
    require(newInterestRateModel.isInterestRateModel(), "marker method returned false");

    // Set the interest rate model to newInterestRateModel
    interestRateModel = newInterestRateModel;

    // Emit NewMarketInterestRateModel(oldInterestRateModel, newInterestRateModel)
    emit NewMarketInterestRateModel(oldInterestRateModel, newInterestRateModel);

    return NO_ERROR;
}

function _upgrade(
  address controller, address beacon, address implementation
) private {
  // Ensure that the implementaton contract is not the null address.
  require(
    implementation != address(0),
    "Implementation cannot be the null address."
  );

  // Ensure that the implementation contract has code via extcodesize.
  uint256 size;
  assembly {
    size := extcodesize(implementation)
  }
  require(size > 0, "Implementation must have contract code.");

  // Try to get current implementation and store it as a prior implementation.
  (bool ok, bytes memory returnData) = beacon.call("");
  if (ok && returnData.length == 32) {
    address currentImplementation = abi.decode(returnData, (address));

    _implementations[controller][beacon].push(PriorImplementation({
      implementation: currentImplementation,
      rollbackBlocked: false
    }));
  }

  // Trigger the upgrade to the new implementation contract.
  UpgradeBeaconControllerInterface(controller).upgrade(
    beacon, implementation
  );
}

function __setLiquidationIncentive(
    uint96 poolId,
    address vToken,
    uint256 newLiquidationIncentiveMantissa
)
    internal
    compareValue(
        _poolMarkets[getPoolMarketIndex(poolId, vToken)].liquidationIncentiveMantissa,
        newLiquidationIncentiveMantissa
    )
    returns (uint256)
{
    // Check if pool exists
    if (poolId > lastPoolId) revert PoolDoesNotExist(poolId);

    // Verify market is listed in the pool
    Market storage market = _poolMarkets[getPoolMarketIndex(poolId, vToken)];
    ensureListed(market);

    require(newLiquidationIncentiveMantissa >= mantissaOne, "incentive < 1e18");

    emit NewLiquidationIncentive(
        poolId,
        vToken,
        market.liquidationIncentiveMantissa,
        newLiquidationIncentiveMantissa
    );

    // Set liquidation incentive to new incentive
    market.liquidationIncentiveMantissa = newLiquidationIncentiveMantissa;

    return uint256(Error.NO_ERROR);
}

function _tradeDodo(
    IERC20Token sellToken,
    uint256 sellAmount,
    bytes memory bridgeData
) internal returns (uint256 boughtAmount) {
    (IDODOHelper helper, IDODO pool, bool isSellBase) = abi.decode(bridgeData, (IDODOHelper, IDODO, bool));

    // Grant the Dodo pool contract an allowance to sell the first token.
    sellToken.approveIfBelow(address(pool), sellAmount);

    if (isSellBase) {
        // Sell the Base token directly against the contract
        boughtAmount = pool.sellBaseToken(
            // amount to sell
            sellAmount,
            // min receive amount
            1,
            new bytes(0)
        );
    } else {
        // Need to re-calculate the sell quote amount into buyBase
        boughtAmount = helper.querySellQuoteToken(pool, sellAmount);
        pool.buyBaseToken(
            // amount to buy
            boughtAmount,
            // max pay amount
            sellAmount,
            new bytes(0)
        );
    }

    return boughtAmount;
}

function initializePublicationCollectModule(
    uint256 profileId,
    uint256 pubId,
    address /* transactionExecutor */,
    bytes calldata data
) external override onlyActionModule returns (bytes memory) {
    ProtocolSharedRevenueMinFeeMintModuleInitData memory initData = abi.decode(
        data,
        (ProtocolSharedRevenueMinFeeMintModuleInitData)
    );

    BaseFeeCollectModuleInitData memory baseInitData = BaseFeeCollectModuleInitData({
        amount: initData.amount,
        collectLimit: initData.collectLimit,
        currency: initData.currency,
        referralFee: initData.referralFee,
        followerOnly: initData.followerOnly,
        endTimestamp: initData.endTimestamp,
        recipient: initData.recipient
    });

    if (initData.creatorClient != address(0)) {
        _creatorClientByPublicationByProfile[profileId][pubId] = initData.creatorClient;
    }

    _validateBaseInitData(baseInitData);
    _storeBasePublicationCollectParameters(profileId, pubId, baseInitData);
    return data;
}

constructor(ComptrollerInterface comptroller_,
                InterestRateModel interestRateModel_,
                uint initialExchangeRateMantissa_,
                string memory name_,
                string memory symbol_,
                uint decimals_) internal {
        // Set admin to msg.sender
        admin = msg.sender;

        // Set initial exchange rate
        initialExchangeRateMantissa = initialExchangeRateMantissa_;
        require(initialExchangeRateMantissa > 0, "Initial exchange rate must be greater than zero.");

        // Set the comptroller
        uint err = _setComptroller(comptroller_);
        require(err == uint(Error.NO_ERROR), "Setting comptroller failed");

        // Initialize block number and borrow index (block number mocks depend on comptroller being set)
        accrualBlockNumber = getBlockNumber();
        borrowIndex = mantissaOne;

        // Set the interest rate model (depends on block number / borrow index)
        err = _setInterestRateModelFresh(interestRateModel_);
        require(err == uint(Error.NO_ERROR), "Setting interest rate model failed");

        name = name_;
        symbol = symbol_;
        decimals = decimals_;
    }

function _calculateWithdrawActionAndFinalize(
    address account,
    AccountContext memory accountContext,
    BalanceState memory balanceState,
    uint256 withdrawAmountInternalPrecision,
    bool withdrawEntireCashBalance,
    bool redeemToUnderlying
) private {
    int256 withdrawAmount = int256(withdrawAmountInternalPrecision);
    require(withdrawAmount >= 0); // dev: withdraw action overflow

    if (withdrawEntireCashBalance) {
        // This option is here so that accounts do not end up with dust after lending since we generally
        // cannot calculate exact cash amounts from the liquidity curve.
        withdrawAmount = balanceState.storedCashBalance.add(balanceState.netCashChange).add(
            balanceState.netAssetTransferInternalPrecision
        );

        // If the account has a negative cash balance then cannot withdraw
        if (withdrawAmount < 0) withdrawAmount = 0;
    }

    // prettier-ignore
    balanceState.netAssetTransferInternalPrecision = balanceState
        .netAssetTransferInternalPrecision
        .sub(withdrawAmount);

    balanceState.finalize(account, accountContext, redeemToUnderlying);
}

function _finalizeLiquidatorBalances(
    uint256 localCurrency,
    uint256 collateralCurrency,
    int256 localAssetCashFromLiquidator,
    BalanceState memory collateralBalanceState,
    bool withdrawCollateral,
    bool redeemToUnderlying
) private {
    // Will transfer local currency from the liquidator
    AccountContext memory liquidatorContext =
        LiquidationHelpers.finalizeLiquidatorLocal(
            msg.sender,
            localCurrency,
            localAssetCashFromLiquidator,
            0 // No nToken transfers
        );

    // Will transfer collateral to the liquidator
    LiquidationHelpers.finalizeLiquidatorCollateral(
        msg.sender,
        liquidatorContext,
        collateralCurrency,
        _collateralAssetCashToLiquidator(collateralBalanceState),
        collateralBalanceState.netNTokenTransfer.neg(),
        withdrawCollateral,
        redeemToUnderlying
    );

    liquidatorContext.setAccountContext(msg.sender);
}

function _getResidualPriceAssetCash(
    CashGroupParameters memory cashGroup,
    uint256 maturity,
    uint256 blockTime,
    int256 fCashAmount,
    bytes6 parameters
) internal view returns (int256) {
    uint256 oracleRate = cashGroup.calculateOracleRate(maturity, blockTime);
    uint256 purchaseIncentive =
        uint256(uint8(parameters[Constants.RESIDUAL_PURCHASE_INCENTIVE])) *
            10 *
            Constants.BASIS_POINT;

    if (fCashAmount > 0) {
        oracleRate = oracleRate.add(purchaseIncentive);
    } else if (oracleRate > purchaseIncentive) {
        oracleRate = oracleRate.sub(purchaseIncentive);
    } else {
        // If the oracle rate is less than the purchase incentive floor the interest rate at zero
        oracleRate = 0;
    }

    int256 exchangeRate =
        Market.getExchangeRateFromImpliedRate(oracleRate, maturity.sub(blockTime));

    // Returns the net asset cash from the nToken perspective, which is the same sign as the fCash amount
    return
        cashGroup.assetRate.convertFromUnderlying(fCashAmount.divInRatePrecision(exchangeRate));
}

function loadBalanceState(
    BalanceState memory balanceState,
    address account,
    uint256 currencyId,
    AccountContext memory accountContext
) internal view {
    require(currencyId != 0); // dev: invalid currency id
    balanceState.currencyId = currencyId;

    if (accountContext.isActiveInBalances(currencyId)) {
        (
            balanceState.storedCashBalance,
            balanceState.storedNTokenBalance,
            balanceState.lastClaimTime,
            balanceState.lastClaimIntegralSupply
        ) = getBalanceStorage(account, currencyId);
    } else {
        balanceState.storedCashBalance = 0;
        balanceState.storedNTokenBalance = 0;
        balanceState.lastClaimTime = 0;
        balanceState.lastClaimIntegralSupply = 0;
    }

    balanceState.netCashChange = 0;
    balanceState.netAssetTransferInternalPrecision = 0;
    balanceState.netNTokenTransfer = 0;
    balanceState.netNTokenSupplyChange = 0;
}

function calculateLiquidationAmount(
    int256 initialAmountToLiquidate,
    int256 maxTotalBalance,
    int256 userSpecifiedMaximum
) internal pure returns (int256) {
    // By default, the liquidator is allowed to purchase at least to `defaultAllowedAmount`
    // if `initialAmountToLiquidate` is less than `defaultAllowedAmount`.
    int256 defaultAllowedAmount =
        maxTotalBalance.mul(Constants.DEFAULT_LIQUIDATION_PORTION).div(
            Constants.PERCENTAGE_DECIMALS
        );

    int256 result = initialAmountToLiquidate;

    // Limit the purchase amount by the max total balance, we cannot purchase
    // more than what is available.
    if (initialAmountToLiquidate > maxTotalBalance) {
        result = maxTotalBalance;
    }

    if (initialAmountToLiquidate < defaultAllowedAmount) {
        // Allow the liquidator to go up to the default allowed amount
        result = defaultAllowedAmount;
    }

    if (userSpecifiedMaximum > 0 && result > userSpecifiedMaximum) {
        // Do not allow liquidation above the user specified maximum
        result = userSpecifiedMaximum;
    }

    return result;
}

function getUpdatedCurrentStaker() public returns (address) {
    uint256 currentStake =
        getMaintenanceStakerStake(currentMaintenanceStaker);
    while (
        (block.number - currentMaintenanceStakerStartBlock) *
            maintenanceStakePerBlock >=
        currentStake
    ) {
        if (maintenanceStakePerBlock > currentStake) {
            // delete current from daisy chain
            address nextOne =
                nextMaintenanceStaker[currentMaintenanceStaker];
            nextMaintenanceStaker[prevMaintenanceStaker] = nextOne;
            nextMaintenanceStaker[currentMaintenanceStaker] = address(0);

            currentMaintenanceStaker = nextOne;
        } else {
            currentMaintenanceStakerStartBlock +=
                currentStake /
                maintenanceStakePerBlock;

            prevMaintenanceStaker = currentMaintenanceStaker;
            currentMaintenanceStaker = nextMaintenanceStaker[
                currentMaintenanceStaker
            ];
        }
        currentStake = getMaintenanceStakerStake(currentMaintenanceStaker);
    }
    return currentMaintenanceStaker;
}

function reverse(bytes calldata reverseName)
        external
        view
        returns (
            string memory,
            address,
            address,
            address
        )
    {
        (
            bytes memory resolvedReverseData,
            address reverseResolverAddress
        ) = this.resolve(
                reverseName,
                abi.encodeCall(INameResolver.name, reverseName.namehash(0))
            );

        string memory resolvedName = abi.decode(resolvedReverseData, (string));

        (bytes memory encodedName, bytes32 namehash) = resolvedName
            .dnsEncodeName();

        (bytes memory resolvedData, address resolverAddress) = this.resolve(
            encodedName,
            abi.encodeCall(IAddrResolver.addr, namehash)
        );

        address resolvedAddress = abi.decode(resolvedData, (address));

        return (
            resolvedName,
            resolvedAddress,
            reverseResolverAddress,
            resolverAddress
        );
    }

